{{ (() => {
  const msg = typeof $json.message === 'string'
    ? JSON.parse($json.message.trim().replace(/,\s*$/, ''))
    : ($json.message ?? $json);

  const execution = $json.execution ?? {};
  const workflow = $json.workflow ?? {};

  const payload = {
    ...msg,

    source: 'n8n',

    n8n_execution_id: String(execution.id ?? $execution.id ?? ''),
    n8n_execution_mode: execution.mode ?? '',
    n8n_resume_url: execution.resumeUrl ?? '',
    n8n_resume_form_url: execution.resumeFormUrl ?? '',

    n8n_workflow_id: String(workflow.id ?? $workflow.id ?? ''),
    n8n_workflow_name: workflow.name ?? $workflow.name ?? '',
    n8n_workflow_active: workflow.active ?? null,

    n8n_node_name: 'Log SLA Case to Supabase'
  };

  // Keep real SLA states: RED / ORANGE / YELLOW / GREEN
  const currentSla = String(payload.sla_status || '').toUpperCase();

  if (currentSla) {
    payload.sla_status = currentSla;
  }

  // Normalize SLA labels, but do NOT convert ORANGE to YELLOW
  if (Array.isArray(payload.labels)) {
    payload.labels = payload.labels.map(label => {
      const text = String(label || '');

      if (text.toLowerCase() === 'sla:red') return 'sla:RED';
      if (text.toLowerCase() === 'sla:orange') return 'sla:ORANGE';
      if (text.toLowerCase() === 'sla:yellow') return 'sla:YELLOW';
      if (text.toLowerCase() === 'sla:green') return 'sla:GREEN';

      return label;
    });
  }

  const safePayload = JSON.stringify(payload).replace(/'/g, "''");

  return `SELECT public.process_email_sla_case('${safePayload}'::jsonb) AS result;`;
})() }}

