// Gmail Pre-Filter: skip emails with blocked labels
// Add or remove labels from this list to customize

const items = $input.all();
const results = [];

const blockedLabels = [
  'SENT',
  'DRAFT',
  'SPAM',
  'TRASH',
  'CATEGORY_PROMOTIONS',
  'CATEGORY_SOCIAL',
  'CATEGORY_UPDATES',
  'CATEGORY_FORUMS',
  'Marketing'
];

for (const item of items) {
  const labels = (item.json.labels || []).map(label => {
    if (typeof label === 'string') return label;
    return label.name || label.id || '';
  }).filter(Boolean);

  const hasBlockedLabel = labels.some(l => blockedLabels.includes(l));

  if (!hasBlockedLabel) {
    results.push(item);
  }
}

return results;

const MAX_BODY_CHARS = 3000;
const MAX_RAW_DECODE_CHARS = 800000; // safety cap before cleaning large emails

const items = $input.all();

function toText(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  return typeof value === 'string' ? value : String(value);
}

function getHeader(headers, name) {
  if (!Array.isArray(headers)) return '';
  const found = headers.find(h => String(h.name || '').toLowerCase() === name.toLowerCase());
  return found?.value || '';
}

function parseEmailAddress(raw) {
  if (!raw) {
    return {
      raw: '',
      email: 'unknown',
      name: ''
    };
  }

  if (typeof raw === 'object') {
    if (Array.isArray(raw.value) && raw.value[0]) {
      const address = raw.value[0].address || 'unknown';
      const name = raw.value[0].name || '';

      return {
        raw: name ? `${name} <${address}>` : address,
        email: address,
        name
      };
    }

    if (raw.address) {
      const address = raw.address || 'unknown';
      const name = raw.name || '';

      return {
        raw: name ? `${name} <${address}>` : address,
        email: address,
        name
      };
    }

    return {
      raw: JSON.stringify(raw),
      email: 'unknown',
      name: ''
    };
  }

  const text = String(raw).trim();

  const angleMatch = text.match(/<([^>]+)>/);
  if (angleMatch) {
    const email = angleMatch[1].trim();
    const name = text.replace(/<[^>]+>/, '').replace(/^"|"$/g, '').trim();

    return {
      raw: text,
      email,
      name
    };
  }

  const emailMatch = text.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  if (emailMatch) {
    return {
      raw: text,
      email: emailMatch[0].trim(),
      name: ''
    };
  }

  return {
    raw: text,
    email: text || 'unknown',
    name: ''
  };
}

function formatAddressField(value) {
  if (value === null || value === undefined || value === '') return '';

  if (typeof value === 'string') return value;

  if (Array.isArray(value)) {
    return value
      .map(formatAddressField)
      .filter(Boolean)
      .join(', ');
  }

  if (typeof value === 'object') {
    if (Array.isArray(value.value)) {
      return value.value
        .map(v => {
          const address = v?.address || '';
          const name = v?.name || '';
          return name && address ? `${name} <${address}>` : address || name;
        })
        .filter(Boolean)
        .join(', ');
    }

    if (Array.isArray(value.addresses)) {
      return value.addresses
        .map(formatAddressField)
        .filter(Boolean)
        .join(', ');
    }

    if (value.address) {
      return value.name
        ? `${value.name} <${value.address}>`
        : value.address;
    }

    if (value.email) {
      return value.name
        ? `${value.name} <${value.email}>`
        : value.email;
    }

    try {
      return JSON.stringify(value);
    } catch (error) {
      return '';
    }
  }

  return String(value);
}

function decodeBase64Url(data) {
  if (!data || typeof data !== 'string') return '';

  try {
    let normalized = data.replace(/-/g, '+').replace(/_/g, '/');

    while (normalized.length % 4) {
      normalized += '=';
    }

    return Buffer.from(normalized, 'base64').toString('utf8');
  } catch (error) {
    return '';
  }
}

function stripHtml(html) {
  if (!html) return '';

  return String(html)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\s+\n/g, '\n')
    .replace(/\n\s+/g, '\n')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function walkParts(part, result = {
  textPlain: [],
  textHtml: [],
  attachments: [],
  mimeTypes: []
}) {
  if (!part || typeof part !== 'object') return result;

  const mimeType = String(part.mimeType || '').toLowerCase();
  const filename = part.filename || '';

  if (mimeType) {
    result.mimeTypes.push(mimeType);
  }

  if (filename) {
    result.attachments.push({
      filename,
      mimeType: part.mimeType || '',
      attachmentId: part.body?.attachmentId || '',
      size: part.body?.size || 0
    });
  }

  const bodyData = part.body?.data;
  if (bodyData) {
    const decoded = decodeBase64Url(bodyData);

    if (decoded) {
      if (mimeType === 'text/plain') {
        result.textPlain.push(decoded);
      } else if (mimeType === 'text/html') {
        result.textHtml.push(decoded);
      }
    }
  }

  if (Array.isArray(part.parts)) {
    for (const child of part.parts) {
      walkParts(child, result);
    }
  }

  return result;
}

function cleanEmailBody(body) {
  let text = toText(body, '');

  if (text.length > MAX_RAW_DECODE_CHARS) {
    text = text.substring(0, MAX_RAW_DECODE_CHARS);
  }

  text = text
    .replace(/https?:\/\/[^\s]+/g, '[link]')
    .replace(/www\.[^\s]+/g, '[link]')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  const originalLength = text.length;
  let truncated = false;

  if (text.length > MAX_BODY_CHARS) {
    text = text.substring(0, MAX_BODY_CHARS) + '\n[truncated]';
    truncated = true;
  }

  return {
    body: text,
    originalLength,
    truncated
  };
}

function parseLabels(email) {
  const labels = [];

  if (Array.isArray(email.labels)) {
    for (const label of email.labels) {
      if (typeof label === 'string') labels.push(label);
      else if (label?.name) labels.push(label.name);
      else if (label?.id) labels.push(label.id);
    }
  }

  if (Array.isArray(email.labelIds)) {
    for (const id of email.labelIds) {
      if (!labels.includes(id)) labels.push(id);
    }
  }

  return labels;
}

function parseInternalDate(email) {
  if (email.internalDate) {
    const date = new Date(Number(email.internalDate));
    if (!Number.isNaN(date.getTime())) return date.toISOString();
  }

  const dateHeader = getHeader(email.payload?.headers, 'Date') || email.Date || email.date;
  if (dateHeader) {
    const date = new Date(dateHeader);
    if (!Number.isNaN(date.getTime())) return date.toISOString();
  }

  return new Date().toISOString();
}

return items.map(item => {
  const email = item.json || {};
  const headers = email.payload?.headers || email.headers || [];

  const parseWarnings = [];

  // Headers / basic fields
  const fromRaw =
    email.From ||
    email.from ||
    getHeader(headers, 'From') ||
    '';

  const parsedFrom = parseEmailAddress(fromRaw);

  const toField =
    email.To ||
    email.to ||
    getHeader(headers, 'To') ||
    '';

  const ccField =
    email.Cc ||
    email.cc ||
    getHeader(headers, 'Cc') ||
    '';

  const subject =
    email.Subject ||
    email.subject ||
    email.headers?.subject ||
    getHeader(headers, 'Subject') ||
    '(no subject)';

  // Body parsing
  let body = '';

  // n8n simplified / alternative fields
  if (typeof email.textPlain === 'string' && email.textPlain.trim()) {
    body = email.textPlain;
  } else if (typeof email.text === 'string' && email.text.trim()) {
    body = email.text;
  }

  // Gmail full payload recursive parse
  const walked = walkParts(email.payload || {});

  if (!body && walked.textPlain.length > 0) {
    body = walked.textPlain.join('\n\n');
  }

  if (!body && walked.textHtml.length > 0) {
    body = stripHtml(walked.textHtml.join('\n\n'));
  }

  // Direct payload body fallback
  if (!body && email.payload?.body?.data) {
    const decoded = decodeBase64Url(email.payload.body.data);

    if (String(email.payload.mimeType || '').toLowerCase() === 'text/html') {
      body = stripHtml(decoded);
    } else {
      body = decoded;
    }
  }

  // HTML fallback from n8n simplified fields
  if (!body && typeof email.textHtml === 'string' && email.textHtml.trim()) {
    body = stripHtml(email.textHtml);
  }

  if (!body && typeof email.html === 'string' && email.html.trim()) {
    body = stripHtml(email.html);
  }

  // Snippet fallback
  if (!body && email.snippet) {
    body = email.snippet;
    parseWarnings.push('body_from_snippet_only');
  }

  // Final fallback: don't break workflow; classify based on subject/from if body missing
  if (!body || !body.trim()) {
    body = `[No readable body found]\nSubject: ${subject}\nFrom: ${parsedFrom.email}`;
    parseWarnings.push('empty_body_fallback_used');
  }

  const cleaned = cleanEmailBody(body);

  // Attachments
  let attachments = [];

  if (Array.isArray(email.attachments)) {
    attachments = email.attachments.map(a => ({
      filename: a.filename || a.fileName || '',
      mimeType: a.mimeType || '',
      attachmentId: a.attachmentId || a.id || '',
      size: a.size || 0
    }));
  }

  if (walked.attachments.length > 0) {
    attachments = [...attachments, ...walked.attachments];
  }

  // Deduplicate attachments
  const attachmentMap = new Map();
  for (const attachment of attachments) {
    const key = `${attachment.filename || ''}:${attachment.attachmentId || ''}:${attachment.size || ''}`;
    attachmentMap.set(key, attachment);
  }
  attachments = Array.from(attachmentMap.values());

  const gmailLabels = parseLabels(email);
  const receivedAt = parseInternalDate(email);
  const processedAt = new Date().toISOString();

  const messageId = email.id || email.message_id || getHeader(headers, 'Message-ID') || '';
  const threadId = email.threadId || email.thread_id || '';

  const toClean = formatAddressField(toField);
  const ccClean = formatAddressField(ccField);

  return {
    json: {
      event_id: messageId,

      sender_email: parsedFrom.email,
      sender_name: parsedFrom.name,
      raw_from: parsedFrom.raw,

      to: toClean,
      cc: ccClean,

      subject: toText(subject, '(no subject)'),
      body: cleaned.body,

      message_id: messageId,
      inbox_id: 'gmail',
      thread_id: threadId,

      existing_labels: gmailLabels,
      thread_labels: gmailLabels,
      thread_message_count: 1,

      has_attachments: attachments.length > 0,
      attachment_count: attachments.length,
      attachment_names: attachments.map(a => a.filename).filter(Boolean),
      attachments_metadata: attachments,

      gmail_size_estimate: email.sizeEstimate || null,
      mime_types_seen: Array.from(new Set(walked.mimeTypes)).slice(0, 30),

      body_original_length: cleaned.originalLength,
      body_truncated: cleaned.truncated,
      parse_warnings: parseWarnings,

      received_at: receivedAt,
      processed_at: processedAt
    }
  };
});

