// Build 4 lean labels + merge all data for downstream

const raw = $input.first().json;
const triage = raw.output || raw;
const labels = [];

// === 4 LABELS ===
if (triage.sla_status) labels.push(`sla:${triage.sla_status}`);
if (triage.inquiry_category) labels.push(`pipeline:${triage.inquiry_category}`);
if (triage.stucco_priority) labels.push(`priority:${triage.stucco_priority}`);
if (triage.sentiment) labels.push(`sentiment:${triage.sentiment}`);

// === GET EMAIL DATA (loop-safe) ===
let emailData;
try {
  emailData = $('Extract Email Info for Classification').item.json;
} catch (e) {
  emailData = $('Extract Email Info for Classification').first().json;
}

return [{
  json: {
    labels: labels,
    message_id: emailData.message_id,
    inbox_id: emailData.inbox_id,
    thread_id: emailData.thread_id,
    event_id: emailData.event_id,
    sla_status: triage.sla_status,
    owner_alert: triage.owner_alert,
    helen_action: triage.helen_action,
    response_deadline: triage.response_deadline,
    stucco_priority: triage.stucco_priority,
    inquiry_category: triage.inquiry_category,
    sentiment: triage.sentiment,
    category: triage.category,
    department: triage.department,
    property_type: triage.property_type,
    technical_specs: triage.technical_specs,
    sender_email: emailData.sender_email,
    subject: emailData.subject,
    body: emailData.body,
    received_at: emailData.received_at,
    processed_at: new Date().toISOString()
  }
}];

// Build Mem0 payload directly from triage data
// No CRM mapping needed — all context goes to memory

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // === SAFE sender extraction ===
  let senderEmail = 'unknown';
  const rawFrom = data.raw_from || data.sender_email || '';

  if (typeof rawFrom === 'string' && rawFrom.length > 0) {
    if (rawFrom.includes('<') && rawFrom.includes('>')) {
      senderEmail = rawFrom.split('<')[1].split('>')[0].trim();
    } else {
      senderEmail = rawFrom.trim();
    }
  } else if (typeof rawFrom === 'object' && rawFrom !== null) {
    // Gmail object format: {value: [{address: '...', name: '...'}]}
    if (rawFrom.value && rawFrom.value[0]) {
      senderEmail = rawFrom.value[0].address || 'unknown';
    } else if (rawFrom.address) {
      senderEmail = rawFrom.address;
    }
  }

  // === SAFE sender name ===
  let contactName = senderEmail;
  if (typeof rawFrom === 'string' && rawFrom.includes('<')) {
    contactName = rawFrom.split('<')[0].trim() || senderEmail;
  } else if (typeof rawFrom === 'object' && rawFrom?.value?.[0]?.name) {
    contactName = rawFrom.value[0].name;
  }

  // === BUILD MEMORY CONTENT ===
  const memoryContent = [
    `Subject: ${data.subject || '(no subject)'}`,
    `From: ${contactName} <${senderEmail}>`,
    `SLA: ${data.sla_status || 'unknown'}`,
    `Priority: ${data.stucco_priority || 'unknown'}`,
    `Pipeline: ${data.inquiry_category || 'unknown'}`,
    `Sentiment: ${data.sentiment || 'unknown'}`,
    `Category: ${data.category || 'unknown'}`,
    `Department: ${data.department || 'unknown'}`,
    `Specs: ${data.technical_specs || 'unknown'}`,
    `Property: ${data.property_type || 'unknown'}`,
    `Deadline: ${data.response_deadline || 'unknown'}`,
    '',
    data.body || '(no body)'
  ].join('\n');

  // === BUILD LABELS STRING ===
  let labelsStr = '';
  if (Array.isArray(data.labels)) {
    labelsStr = data.labels.join(', ');
  } else if (typeof data.labels === 'string') {
    labelsStr = data.labels;
  }

  // === MEM0 PAYLOAD ===
  results.push({
    json: {
      user_id: senderEmail,
      agent_id: 'stuccoos_triage',
      app_id: 'stuccoos_gmail',
      run_id: data.thread_id || data.message_id || '',
      messages: [
        {
          role: 'user',
          content: memoryContent
        }
      ],
      metadata: {
        email_id: data.message_id || '',
        thread_id: data.thread_id || '',
        subject: data.subject || '',
        sla_status: data.sla_status || '',
        priority: data.stucco_priority || '',
        pipeline: data.inquiry_category || '',
        sentiment: data.sentiment || '',
        category: data.category || '',
        department: data.department || '',
        property_type: data.property_type || '',
        technical_specs: data.technical_specs || '',
        response_deadline: data.response_deadline || '',
        owner_alert: data.owner_alert || 'false',
        helen_action: data.helen_action || 'false',
        labels: labelsStr,
        contact_name: contactName,
        source: 'gmail_triage',
        date: data.received_at || new Date().toISOString()
      },
      infer: true,
      output_format: 'v1.1'
    }
  });
}

return results;

