  const text = toText(value, '');
  return text.length > max ? `${text.substring(0, max)}...` : text;
};

const parseDeadlineHours = (value, fallback = 24) => {
  const match = toText(value, '').match(/(\d+)/);
  return match ? Number(match[1]) : fallback;
};

const dueFromReceivedAt = (receivedAt, hours) => {
  const base = receivedAt ? new Date(receivedAt) : new Date();
  const safeBase = Number.isNaN(base.getTime()) ? new Date() : base;
  return new Date(safeBase.getTime() + hours * 60 * 60 * 1000).toISOString();
};

return $input.all().map(item => {
