      action_type: 'standard_task',
      action_status: 'prepared',
      action_created_at: new Date().toISOString()
    }
  };
});

const toText = (value, fallback = '') => {
  if (value === null || value === undefined) return fallback;
  return typeof value === 'string' ? value : String(value);
};

const nextCheckInHours = (hours) => {
  return new Date(Date.now() + hours * 60 * 60 * 1000).toISOString();
};

return $input.all().map(item => {
  const data = item.json || {};
  const labels = Array.isArray(data.labels) ? data.labels : [];

  return {
    json: {
      ...data,
      status: 'logged',
      note: `No immediate action needed. ${labels.length} labels applied. 48h timer started.`,
      next_check: nextCheckInHours(48),
      action_type: 'delay_48h',
      action_status: 'logged',
      action_created_at: new Date().toISOString(),
      sender_email: toText(data.sender_email, 'Unknown'),
      subject: toText(data.subject, 'No Subject')
    }
  };
});

