DROP VIEW IF EXISTS public.v_sla_owner_alerts;
DROP VIEW IF EXISTS public.v_sla_done;
DROP VIEW IF EXISTS public.v_sla_green;
DROP VIEW IF EXISTS public.v_sla_yellow;
DROP VIEW IF EXISTS public.v_sla_orange;
DROP VIEW IF EXISTS public.v_sla_red;
DROP VIEW IF EXISTS public.v_email_sla_board;

CREATE VIEW public.v_email_sla_board AS
SELECT
  c.*,
  CASE
    WHEN c.closed_at IS NOT NULL OR c.case_status = 'closed' THEN 'DONE'
    WHEN c.case_status IN ('spam','ignored') THEN 'DONE'
    WHEN c.sla_due_at IS NOT NULL AND c.closed_at IS NULL AND c.case_status NOT IN ('closed','spam','ignored') AND now() > c.sla_due_at THEN 'RED'
    WHEN upper(coalesce(c.sla_status, '')) = 'RED' THEN 'RED'
    WHEN upper(coalesce(c.sla_status, '')) = 'ORANGE' THEN 'ORANGE'
    WHEN upper(coalesce(c.sla_status, '')) = 'YELLOW' THEN 'YELLOW'
    WHEN upper(coalesce(c.sla_status, '')) = 'GREEN' THEN 'GREEN'
    WHEN c.sla_due_at IS NULL THEN 'UNKNOWN'
    WHEN now() >= c.sla_due_at - interval '1 hour' THEN 'ORANGE'
    WHEN now() >= c.sla_due_at - interval '4 hours' THEN 'YELLOW'
    ELSE 'GREEN'
  END AS live_sla_color,
  CASE WHEN c.sla_due_at IS NULL THEN NULL ELSE floor(extract(epoch FROM c.sla_due_at - now()) / 60)::integer END AS minutes_until_due,
  CASE WHEN c.received_at IS NULL THEN NULL ELSE floor(extract(epoch FROM now() - c.received_at) / 60)::integer END AS age_minutes,
  CASE WHEN c.sla_due_at IS NOT NULL AND c.closed_at IS NULL AND c.case_status NOT IN ('closed','spam','ignored') AND now() > c.sla_due_at THEN true ELSE false END AS is_breached,
  CASE
    WHEN c.closed_at IS NOT NULL AND c.sla_due_at IS NOT NULL AND c.closed_at <= c.sla_due_at THEN true
    WHEN c.closed_at IS NOT NULL AND c.sla_due_at IS NOT NULL AND c.closed_at > c.sla_due_at THEN false
    ELSE NULL
  END AS closed_within_sla
FROM public.email_sla_cases c;

CREATE VIEW public.v_sla_red AS SELECT * FROM public.v_email_sla_board WHERE live_sla_color = 'RED' ORDER BY sla_due_at ASC NULLS LAST;
CREATE VIEW public.v_sla_orange AS SELECT * FROM public.v_email_sla_board WHERE live_sla_color = 'ORANGE' ORDER BY sla_due_at ASC NULLS LAST;
CREATE VIEW public.v_sla_yellow AS SELECT * FROM public.v_email_sla_board WHERE live_sla_color = 'YELLOW' ORDER BY sla_due_at ASC NULLS LAST;
CREATE VIEW public.v_sla_green AS SELECT * FROM public.v_email_sla_board WHERE live_sla_color = 'GREEN' ORDER BY sla_due_at ASC NULLS LAST;
CREATE VIEW public.v_sla_done AS SELECT * FROM public.v_email_sla_board WHERE live_sla_color = 'DONE' ORDER BY closed_at DESC NULLS LAST, updated_at DESC;
CREATE VIEW public.v_sla_owner_alerts AS SELECT * FROM public.v_email_sla_board WHERE owner_alert = true AND case_status IN ('open','waiting_customer') AND closed_at IS NULL ORDER BY sla_due_at ASC NULLS LAST;

CREATE OR REPLACE FUNCTION public.log_email_sla_event(p_event jsonb)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_log_id uuid;
  v_case_id uuid;
  v_message_id text;
BEGIN
  IF p_event IS NULL THEN
    RAISE EXCEPTION 'p_event is required';
  END IF;

  v_message_id := nullif(trim(p_event->>'message_id'), '');

  IF p_event ? 'case_id' AND nullif(trim(p_event->>'case_id'), '') IS NOT NULL THEN
    v_case_id := (p_event->>'case_id')::uuid;
  ELSIF v_message_id IS NOT NULL THEN
    SELECT id INTO v_case_id FROM public.email_sla_cases WHERE message_id = v_message_id LIMIT 1;
  END IF;

  INSERT INTO public.email_sla_events (
    case_id, message_id, event_type, event_status, source,
    workflow_id, workflow_name, node_name, execution_id, execution_url,
    note, payload, error
  ) VALUES (
    v_case_id,
    v_message_id,
    COALESCE(nullif(trim(p_event->>'event_type'), ''), 'note'),
    COALESCE(nullif(trim(p_event->>'event_status'), ''), 'info'),
    COALESCE(nullif(trim(p_event->>'source'), ''), 'n8n'),
    COALESCE(nullif(trim(p_event->>'workflow_id'), ''), nullif(trim(p_event->>'n8n_workflow_id'), '')),
    COALESCE(nullif(trim(p_event->>'workflow_name'), ''), nullif(trim(p_event->>'n8n_workflow_name'), '')),
    COALESCE(nullif(trim(p_event->>'node_name'), ''), nullif(trim(p_event->>'n8n_node_name'), '')),
    COALESCE(nullif(trim(p_event->>'execution_id'), ''), nullif(trim(p_event->>'n8n_execution_id'), '')),
    COALESCE(nullif(trim(p_event->>'execution_url'), ''), nullif(trim(p_event->>'n8n_execution_url'), ''), nullif(trim(p_event->>'n8n_resume_url'), '')),
    nullif(trim(p_event->>'note'), ''),
    COALESCE(p_event->'payload', p_event, '{}'::jsonb),
    p_event->'error'
  ) RETURNING id INTO v_log_id;

  RETURN v_log_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.process_email_sla_case(payload jsonb)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_case_id uuid;
  v_existing_id uuid;
  v_message_id text;
  v_labels text[];
  v_owner_alert boolean;
  v_helen_action boolean;
  v_response_deadline text;
  v_response_deadline_hours integer;
  v_received_at timestamptz;
  v_processed_at timestamptz;
  v_sla_due_at timestamptz;
  v_sla_status text;
  v_event_type text;
BEGIN
  IF payload IS NULL THEN
    RAISE EXCEPTION 'payload is required';
  END IF;

  v_message_id := nullif(trim(payload->>'message_id'), '');
  IF v_message_id IS NULL THEN
    RAISE EXCEPTION 'message_id is required';
  END IF;

  SELECT id INTO v_existing_id FROM public.email_sla_cases WHERE message_id = v_message_id LIMIT 1;

  SELECT COALESCE(array_agg(x.value), ARRAY[]::text[])
  INTO v_labels
  FROM jsonb_array_elements_text(COALESCE(payload->'labels', '[]'::jsonb)) AS x(value);

  v_sla_status := nullif(upper(trim(payload->>'sla_status')), '');
  IF v_sla_status IS NULL OR v_sla_status NOT IN ('GREEN','YELLOW','ORANGE','RED','DONE','BREACHED','UNKNOWN') THEN
    v_sla_status := 'UNKNOWN';
  END IF;

  v_owner_alert := lower(COALESCE(payload->>'owner_alert', 'false')) IN ('true','1','yes');
  v_helen_action := lower(COALESCE(payload->>'helen_action', 'false')) IN ('true','1','yes');
  v_response_deadline := nullif(trim(payload->>'response_deadline'), '');

  v_response_deadline_hours := COALESCE(
    nullif(regexp_replace(COALESCE(payload->>'response_deadline_hours', v_response_deadline, '24h'), '[^0-9]', '', 'g'), '')::integer,
    24
  );

  v_received_at := COALESCE(nullif(trim(payload->>'received_at'), '')::timestamptz, now());
  v_processed_at := COALESCE(nullif(trim(payload->>'processed_at'), '')::timestamptz, now());
  v_sla_due_at := COALESCE(nullif(trim(payload->>'sla_due_at'), '')::timestamptz, v_received_at + make_interval(hours => v_response_deadline_hours));

  IF v_existing_id IS NULL THEN
    INSERT INTO public.email_sla_cases (
      message_id, inbox_id, thread_id, event_id,
      n8n_execution_id, n8n_workflow_id, n8n_workflow_name, n8n_execution_url,
      sender_email, subject, body, labels, sla_status, case_status,
      owner_alert, helen_action, response_deadline, response_deadline_hours,
      received_at, processed_at, sla_due_at,
      stucco_priority, inquiry_category, sentiment, category, department,
      property_type, technical_specs, raw_payload
    ) VALUES (
      v_message_id,
      COALESCE(nullif(trim(payload->>'inbox_id'), ''), 'gmail'),
      nullif(trim(payload->>'thread_id'), ''),
      nullif(trim(payload->>'event_id'), ''),
      nullif(trim(payload->>'n8n_execution_id'), ''),
      nullif(trim(payload->>'n8n_workflow_id'), ''),
      nullif(trim(payload->>'n8n_workflow_name'), ''),
      COALESCE(nullif(trim(payload->>'n8n_execution_url'), ''), nullif(trim(payload->>'n8n_resume_url'), '')),
      nullif(trim(payload->>'sender_email'), ''),
      nullif(trim(payload->>'subject'), ''),
      nullif(payload->>'body', ''),
      v_labels,
      v_sla_status,
      COALESCE(nullif(trim(payload->>'case_status'), ''), 'open'),
      v_owner_alert,
      v_helen_action,
      v_response_deadline,
      v_response_deadline_hours,
      v_received_at,
      v_processed_at,
      v_sla_due_at,
      nullif(trim(payload->>'stucco_priority'), ''),
      nullif(trim(payload->>'inquiry_category'), ''),
      nullif(trim(payload->>'sentiment'), ''),
      nullif(trim(payload->>'category'), ''),
      nullif(trim(payload->>'department'), ''),
      nullif(trim(payload->>'property_type'), ''),
      nullif(trim(payload->>'technical_specs'), ''),
      payload
    ) RETURNING id INTO v_case_id;

    v_event_type := 'created';
  ELSE
    v_case_id := v_existing_id;

    UPDATE public.email_sla_cases SET
      inbox_id = COALESCE(nullif(trim(payload->>'inbox_id'), ''), inbox_id),
      thread_id = COALESCE(nullif(trim(payload->>'thread_id'), ''), thread_id),
      event_id = COALESCE(nullif(trim(payload->>'event_id'), ''), event_id),
      n8n_execution_id = COALESCE(nullif(trim(payload->>'n8n_execution_id'), ''), n8n_execution_id),
      n8n_workflow_id = COALESCE(nullif(trim(payload->>'n8n_workflow_id'), ''), n8n_workflow_id),
      n8n_workflow_name = COALESCE(nullif(trim(payload->>'n8n_workflow_name'), ''), n8n_workflow_name),
      n8n_execution_url = COALESCE(nullif(trim(payload->>'n8n_execution_url'), ''), nullif(trim(payload->>'n8n_resume_url'), ''), n8n_execution_url),
      sender_email = COALESCE(nullif(trim(payload->>'sender_email'), ''), sender_email),
      subject = COALESCE(nullif(trim(payload->>'subject'), ''), subject),
      body = COALESCE(nullif(payload->>'body', ''), body),
      labels = v_labels,
      sla_status = COALESCE(v_sla_status, sla_status),
      owner_alert = v_owner_alert,
      helen_action = v_helen_action,
      response_deadline = COALESCE(v_response_deadline, response_deadline),
      response_deadline_hours = COALESCE(v_response_deadline_hours, response_deadline_hours),
      received_at = COALESCE(v_received_at, received_at),
      processed_at = COALESCE(v_processed_at, processed_at),
      sla_due_at = COALESCE(v_sla_due_at, sla_due_at),
      stucco_priority = COALESCE(nullif(trim(payload->>'stucco_priority'), ''), stucco_priority),
      inquiry_category = COALESCE(nullif(trim(payload->>'inquiry_category'), ''), inquiry_category),
      sentiment = COALESCE(nullif(trim(payload->>'sentiment'), ''), sentiment),
      category = COALESCE(nullif(trim(payload->>'category'), ''), category),
      department = COALESCE(nullif(trim(payload->>'department'), ''), department),
      property_type = COALESCE(nullif(trim(payload->>'property_type'), ''), property_type),
      technical_specs = COALESCE(nullif(trim(payload->>'technical_specs'), ''), technical_specs),
      raw_payload = payload
    WHERE id = v_case_id;

    v_event_type := 'updated';
  END IF;

  INSERT INTO public.email_sla_events (
    case_id, message_id, event_type, event_status, source,
    workflow_id, workflow_name, node_name, execution_id, execution_url,
    note, payload
  ) VALUES (
    v_case_id,
    v_message_id,
    v_event_type,
    'success',
    COALESCE(nullif(trim(payload->>'source'), ''), 'n8n'),
    nullif(trim(payload->>'n8n_workflow_id'), ''),
    nullif(trim(payload->>'n8n_workflow_name'), ''),
    nullif(trim(payload->>'n8n_node_name'), ''),
    nullif(trim(payload->>'n8n_execution_id'), ''),
    COALESCE(nullif(trim(payload->>'n8n_execution_url'), ''), nullif(trim(payload->>'n8n_resume_url'), '')),
    CASE WHEN v_event_type = 'created' THEN 'SLA case created from n8n email triage' ELSE 'SLA case updated from n8n email triage' END,
    payload
  );

  RETURN jsonb_build_object(
    'status', 'ok',
    'case_id', v_case_id,
    'message_id', v_message_id,
    'event_type', v_event_type,
    'is_new_case', v_existing_id IS NULL,
    'sla_status', v_sla_status,
    'sla_due_at', v_sla_due_at,
    'response_deadline_hours', v_response_deadline_hours
  );
END;
$$;

CREATE OR REPLACE FUNCTION public.close_email_sla_case(
  p_message_id text,
  p_case_status text DEFAULT 'closed',
  p_note text DEFAULT NULL,
  p_event jsonb DEFAULT '{}'::jsonb
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_case_id uuid;
  v_status text;
BEGIN
  IF p_message_id IS NULL OR length(trim(p_message_id)) = 0 THEN
    RAISE EXCEPTION 'p_message_id is required';
  END IF;

  v_status := COALESCE(nullif(trim(p_case_status), ''), 'closed');

  UPDATE public.email_sla_cases SET
    case_status = v_status,
    first_response_at = COALESCE(first_response_at, now()),
    closed_at = CASE WHEN v_status = 'closed' THEN COALESCE(closed_at, now()) ELSE closed_at END
  WHERE message_id = trim(p_message_id)
  RETURNING id INTO v_case_id;

  IF v_case_id IS NULL THEN
    RAISE EXCEPTION 'No email_sla_cases row found for message_id: %', p_message_id;
  END IF;

  INSERT INTO public.email_sla_events (
    case_id, message_id, event_type, event_status, source,
    workflow_id, workflow_name, node_name, execution_id, execution_url,
    note, payload
  ) VALUES (
    v_case_id,
    trim(p_message_id),
    CASE WHEN v_status = 'closed' THEN 'closed' ELSE 'responded' END,
    'success',
    COALESCE(nullif(trim(p_event->>'source'), ''), 'n8n'),
    COALESCE(nullif(trim(p_event->>'workflow_id'), ''), nullif(trim(p_event->>'n8n_workflow_id'), '')),
    COALESCE(nullif(trim(p_event->>'workflow_name'), ''), nullif(trim(p_event->>'n8n_workflow_name'), '')),
    COALESCE(nullif(trim(p_event->>'node_name'), ''), nullif(trim(p_event->>'n8n_node_name'), '')),
    COALESCE(nullif(trim(p_event->>'execution_id'), ''), nullif(trim(p_event->>'n8n_execution_id'), '')),
    COALESCE(nullif(trim(p_event->>'execution_url'), ''), nullif(trim(p_event->>'n8n_execution_url'), ''), nullif(trim(p_event->>'n8n_resume_url'), '')),
    p_note,
    jsonb_build_object('message_id', trim(p_message_id), 'case_status', v_status, 'context', COALESCE(p_event, '{}'::jsonb))
  );

  RETURN jsonb_build_object(
    'status', 'ok',
    'case_id', v_case_id,
    'message_id', trim(p_message_id),
    'case_status', v_status
  );
END;
$$;

